# Shape implementations using utils module
from utils import Color, IMeasurable, IRenderable, Point

class Circle(IMeasurable, IRenderable):
    center: Point
    radius: float
    color: Color

    def __init__(self, center: Point, radius: float, color: Color):
        self.center = center
        self.radius = radius
        self.color = color

    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    def render(self) -> str:
        return f"Circle({self.radius})"

class Rectangle(IMeasurable, IRenderable):
    top_left: Point
    width: float
    height: float

    def __init__(self, top_left: Point, width: float, height: float):
        self.top_left = top_left
        self.width = width
        self.height = height

    def area(self) -> float:
        return self.width * self.height

    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    def render(self) -> str:
        return f"Rectangle({self.width}x{self.height})"

class Triangle(IMeasurable, IRenderable):
    a: Point
    b: Point
    c: Point

    def __init__(self, a: Point, b: Point, c: Point):
        self.a = a
        self.b = b
        self.c = c

    def area(self) -> float:
        # Using shoelace formula
        return 0.5 * ((self.a.x * (self.b.y - self.c.y) + 
                       self.b.x * (self.c.y - self.a.y) + 
                       self.c.x * (self.a.y - self.b.y)))

    def perimeter(self) -> float:
        return (self.a.distance_to(self.b) + 
                self.b.distance_to(self.c) + 
                self.c.distance_to(self.a))

    def render(self) -> str:
        return "Triangle"

