# Collection utilities with generic operations
from utils import Color, ShapeType, IMeasurable

def total_area(shapes: list[IMeasurable]) -> float:
    total: float = 0.0
    for shape in shapes:
        total += shape.area()
    return total

def total_perimeter(shapes: list[IMeasurable]) -> float:
    total: float = 0.0
    for shape in shapes:
        total += shape.perimeter()
    return total

def count_color_occurrences(colors: list[Color], target: Color) -> int:
    count: int = 0
    for c in colors:
        if c == target:
            count += 1
    return count

class ShapeRegistry:
    _shapes: list[str]
    _color_counts: dict[Color, int]

    def __init__(self):
        self._shapes = []
        self._color_counts = {}

    def register(self, name: str, color: Color) -> None:
        self._shapes.append(name)
        current: int = self._color_counts.get(color, 0)
        self._color_counts[color] = current + 1

    def get_shape_count(self) -> int:
        return len(self._shapes)

    def get_color_count(self, color: Color) -> int:
        return self._color_counts.get(color, 0)
